// ❌ BAD - no encapsulation, no abstraction, hard to extend
public class PaymentProcessor
{
    public string CardNumber; // exposed raw field
    public void ProcessVisa() { /* Visa logic hardcoded */ }
    public void ProcessPaypal() { /* PayPal logic hardcoded */ }
}

// ✅ GOOD - all four pillars applied
public abstract class PaymentGateway
{
    private readonly string _merchantId; // encapsulation
    protected PaymentGateway(string merchantId) => _merchantId = merchantId;
    public abstract bool Charge(decimal amount); // abstraction
}

public class StripeGateway : PaymentGateway // inheritance
{
    public StripeGateway(string id) : base(id) { }
    public override bool Charge(decimal amount) => true; // polymorphism
}

// ❌ BAD - violates DIP, SRP, and OCP all at once
public class InvoiceService
{
    public void Process(Invoice invoice)
    {
        var db = new SqlConnection("..."); // hardcoded concretion
        db.Save(invoice);
        new SmtpClient().Send("invoice@co.com", invoice.ToString()); // two responsibilities
    }
}

// ✅ GOOD - DIP via constructor injection, SRP via separate collaborators
public class InvoiceService
{
    private readonly IInvoiceRepository _repo;
    private readonly IEmailNotifier _notifier;
    public InvoiceService(IInvoiceRepository repo, IEmailNotifier notifier)
    { _repo = repo; _notifier = notifier; }
    public void Process(Invoice invoice) { _repo.Save(invoice); _notifier.Notify(invoice); }
}

// ❌ BAD - using interface when shared state is needed, forcing duplication
public interface IReportExporter
{
    string ConnectionString { get; } // every implementer must repeat this
    void Export();
}

// ✅ GOOD - abstract class for shared state + interface for capability
public abstract class ReportExporter
{
    protected string ConnectionString { get; }
    protected ReportExporter(string cs) => ConnectionString = cs;
    public void Export() { var data = FetchData(); WriteOutput(data); } // template method
    protected abstract IEnumerable<string> FetchData();
    protected abstract void WriteOutput(IEnumerable<string> rows);
}

public interface ISchedulable { void RunOnSchedule(string cron); }

public class SalesReportExporter : ReportExporter, ISchedulable
{
    public SalesReportExporter(string cs) : base(cs) { }
    protected override IEnumerable<string> FetchData() => new[] { "row1" };
    protected override void WriteOutput(IEnumerable<string> rows) { }
    public void RunOnSchedule(string cron) { }
}

