public class OrderService
{
    private readonly SqlOrderRepository _repo = new SqlOrderRepository(); // tightly coupled
    public Order GetOrder(int id) => _repo.GetById(id);
}

// ✅ GOOD - constructor injection, registered in Program.cs
// Program.cs
builder.Services.AddScoped<IOrderRepository, SqlOrderRepository>();
builder.Services.AddScoped<IOrderService, OrderService>();

// OrderService.cs
public class OrderService : IOrderService
{
    private readonly IOrderRepository _repo;
    public OrderService(IOrderRepository repo) => _repo = repo;
    public Order GetOrder(int id) => _repo.GetById(id);
}

// ❌ BAD - using new instead of override loses polymorphism
public class Notification
{
    public virtual void Send() => Console.WriteLine("base send");
}
public class EmailNotification : Notification
{
    public new void Send() => Console.WriteLine("email send"); // hiding, not overriding
}
Notification n = new EmailNotification();
n.Send(); // prints "base send" - polymorphism lost

// ✅ GOOD - override enables correct runtime dispatch
public class SmsNotification : Notification
{
    public override void Send() => Console.WriteLine("sms send");
}
Notification n2 = new SmsNotification();
n2.Send(); // prints "sms send" - correct runtime dispatch

// ❌ BAD - using new instead of override, polymorphism broken
public class PricingEngine
{
    public virtual decimal Calculate(decimal basePrice) => basePrice;
}
public class DiscountEngine : PricingEngine
{
    public new decimal Calculate(decimal basePrice) => basePrice * 0.9m; // hiding
}
PricingEngine engine = new DiscountEngine();
engine.Calculate(100); // returns 100, not 90 - wrong!

// ✅ GOOD - override for correct dispatch, sealed to lock the discount logic
public class DiscountEngine : PricingEngine
{
    public sealed override decimal Calculate(decimal basePrice) => basePrice * 0.9m;
}

// ❌ BAD - exposing internal mutable fields publicly, breaks encapsulation
public class BankAccount
{
    public decimal Balance;       // anyone can set this directly
    public string InternalAuditId; // internal detail exposed
}

// ✅ GOOD - correct access modifiers enforce encapsulation
public class BankAccount
{
    public decimal Balance { get; private set; }       // readable publicly, writable only here
    internal string AuditId { get; set; }              // visible in the same assembly for logging
    protected virtual void OnWithdraw(decimal amount) { } // hook for derived classes
    public void Withdraw(decimal amount)
    {
        if (amount > Balance) throw new InvalidOperationException("Insufficient funds");
        Balance -= amount;
        OnWithdraw(amount);
    }
}

// ❌ BAD - mutable static state, not thread-safe, breaks parallel tests
public class OrderService
{
    public static int ProcessedCount = 0; // shared mutable state
    public void Process(Order order) { ProcessedCount++; } // race condition
}

// ✅ GOOD - instance state per object, static only for truly shared read-only data
public class OrderService
{
    private static readonly string _serviceName = "OrderService"; // immutable, safe
    private int _processedInThisSession = 0;                       // per-instance
    public void Process(Order order) { _processedInThisSession++; }
    public static string ServiceName => _serviceName;
}

// ❌ BAD - deep inheritance chain, rigid and fragile
public class Order { }
public class DiscountedOrder : Order { }
public class NotifyingDiscountedOrder : DiscountedOrder { }
public class LoggingNotifyingDiscountedOrder : NotifyingDiscountedOrder { } // explosion

// ✅ GOOD - composition, each behavior is an injectable interface
public class OrderService
{
    private readonly IDiscountStrategy _discount;
    private readonly IOrderNotifier _notifier;
    private readonly IOrderLogger _logger;
    public OrderService(IDiscountStrategy discount, IOrderNotifier notifier, IOrderLogger logger)
    { _discount = discount; _notifier = notifier; _logger = logger; }
    public void PlaceOrder(Order order)
    {
        var price = _discount.Apply(order.Total);
        _notifier.Notify(order);
        _logger.Log(order);
    }
}

// ❌ BAD - using object parameter which causes boxing at compile-time resolution
public class TaxCalculator
{
    public decimal Calculate(object amount) => (decimal)amount * 0.2m; // unboxing cost
}

// ✅ GOOD - compile-time polymorphism via overloads + runtime via virtual
public class TaxCalculator
{
    public decimal Calculate(decimal grossAmount) => grossAmount * 0.20m; // compile-time overload
    public decimal Calculate(int grossAmount) => grossAmount * 0.20m;     // compile-time overload
}

public abstract class TaxStrategy // runtime polymorphism
{
    public abstract decimal ComputeTax(decimal grossAmount);
}
public class VatStrategy : TaxStrategy
{
    public override decimal ComputeTax(decimal grossAmount) => grossAmount * 0.20m;
}

// ❌ BAD - leaving a security-critical class unsealed allows override of validation
public class JwtValidator
{
    public virtual bool Validate(string token) => VerifySignature(token);
    private bool VerifySignature(string token) => true;
}
// A subclass could override Validate and return true without checking the signature

// ✅ GOOD - sealed prevents subclass from bypassing the security logic
public sealed class JwtValidator
{
    public bool Validate(string token) => VerifySignature(token); // no vtable lookup
    private bool VerifySignature(string token) => true;
}
